# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, name):
        self._name = name
        self._balance = 0

    @property
    def balance(self) -> float:
        return self._balance


def process_transaction(account1, account2, amount):
    account1.balance -= amount
    account2.balance += amount
    print(f'{account1._name} transfered {amount:.2f} to {account2._name}. Total for both accounts now: '
          f'${account1.balance} and ${account2.balance}')